import { ViewStates } from '../../types';
import { ensureElement, setElementChildren } from '../../utils/html';
import { Component } from '../base/component';
export class PageView extends Component {
    constructor(container, events) {
        super(container);
        this._catalog = ensureElement('.gallery');
        this._counter = ensureElement('.header__basket-counter');
        this._wrapper = ensureElement('.page__wrapper');
        this._basket = ensureElement('.header__basket');
        this._basket.addEventListener('click', () => {
            events.emit(ViewStates.basketOpen);
        });
    }
    set catalog(items) {
        setElementChildren(this._catalog, items);
    }
    set counter(value) {
        this.setText(this._counter, String(value));
    }
    set locked(value) {
        this.toggleClass(this._wrapper, 'page__wrapper_locked', value);
    }
}
