import { isBoolean, isPlainObject, isSelector } from '.';
/**
 * Убеждается что элемент существует
 * @param selectorElement может быть селектором, элементом или коллекцией элементов
 * @param context
 */
export function ensureElement(selectorElement, context) {
    if (isSelector(selectorElement)) {
        const elements = ensureAllElements(selectorElement, context);
        if (elements.length > 1) {
            console.warn(`selector ${selectorElement} return more then one element`);
        }
        if (elements.length === 0) {
            throw new Error(`selector ${selectorElement} return nothing`);
        }
        return elements.pop();
    }
    if (selectorElement instanceof HTMLElement) {
        return selectorElement;
    }
    throw new Error('Unknown selector element');
}
/**
 * Убеждается что все элементы существуют
 * @param selectorElement
 * @param context
 */
export function ensureAllElements(selectorElement, context = document) {
    if (isSelector(selectorElement)) {
        return Array.from(context.querySelectorAll(selectorElement));
    }
    if (selectorElement instanceof NodeList) {
        return Array.from(selectorElement);
    }
    if (Array.isArray(selectorElement)) {
        return selectorElement;
    }
    throw new Error(`Unknown selector element`);
}
/**
 * Создает элемент и устанавливает ему свойства и дочерние элементы
 */
export function createElement(tagName, props, children) {
    const element = document.createElement(tagName);
    if (props) {
        setElementProps(element, props);
    }
    if (children) {
        setElementChildren(element, children);
    }
    return element;
}
/**
 * Устанавливает дочерние элементы
 */
export function setElementChildren(root, children) {
    root.replaceChildren(...(Array.isArray(children) ? children : [children]));
}
/**
 * Устанавливает свойства элемента
 */
export function setElementProps(element, props) {
    for (const key in props) {
        const value = props[key];
        if (isPlainObject(value) && key === 'dataset') {
            setElementData(element, value);
        }
        else {
            // @ts-expect-error fix indexing
            element[key] = isBoolean(value) ? value : String(value);
        }
    }
}
/**
 * Клонирует элемент из тега template
 */
export function cloneTemplate(query) {
    const template = ensureElement(query);
    const first = template.content.firstElementChild;
    if (!first) {
        throw new Error('Template is empty');
    }
    return first.cloneNode(true);
}
/**
 * Устанавливает dataset атрибуты элемента
 */
export function setElementData(el, data) {
    for (const key in data) {
        el.dataset[key] = String(data[key]);
    }
}
/**
 * Получает типизированные данные из dataset атрибутов элемента
 */
export function getElementData(el, scheme) {
    const data = {};
    for (const key in el.dataset) {
        const parser = scheme[key];
        if (!parser) {
            continue;
        }
        data[key] = parser(el.dataset[key]);
    }
    return data;
}
export function bem(block, element, modifier) {
    let name = block;
    if (element)
        name += `__${element}`;
    if (modifier)
        name += `_${modifier}`;
    return {
        name,
        class: `.${name}`,
    };
}
