import { ViewStates } from '../../../types';
import { ensureElement } from '../../../utils/html';
import { BaseCardView } from './base';
export class CardBasketView extends BaseCardView {
    constructor(container, events) {
        super(container);
        this._index = ensureElement('.basket__item-index', container);
        this._removeButton = ensureElement('.basket__item-delete', container);
        this._removeButton.addEventListener('click', () => {
            if (!this._id)
                return;
            events.emit(ViewStates.basketProductRemove, {
                productId: this._id,
            });
        });
    }
    set index(value) {
        this.setText(this._index, String(value + 1));
    }
    set id(value) {
        this._id = value;
    }
}
