import { ModalStates } from '../../../types';
import { ensureElement, setElementChildren } from '../../../utils/html';
import { Component } from '../../base/component';
export class ModalView extends Component {
    constructor(container, events) {
        super(container);
        this.events = events;
        this._closeButton = ensureElement('.modal__close', container);
        this._content = ensureElement('.modal__content', container);
        this._closeButton.addEventListener('click', this.close.bind(this));
        this.container.addEventListener('click', this.close.bind(this));
        this._content.addEventListener('click', (event) => event.stopPropagation());
    }
    set content(value) {
        if (value === null)
            setElementChildren(this._content, []);
        else
            setElementChildren(this._content, value);
    }
    open() {
        this.container.classList.add('modal_active');
        this.events.emit(ModalStates.open);
    }
    close() {
        this.container.classList.remove('modal_active');
        this.content = null;
        this.events.emit(ModalStates.close);
    }
    render(data) {
        super.render(data);
        this.open();
        return this.container;
    }
}
