import { Api } from '../base/api';
/**
 * Класс для работы с API Веб Ларька
 */
export class LarekApi extends Api {
    constructor(cdn, baseUrl, options) {
        super(baseUrl, options);
        this.cdn = cdn;
    }
    /**
     * Получить список товаров
     */
    async getProductList() {
        return this._get('/product').then((data) => data.items.map((item) => (Object.assign(Object.assign({}, item), { image: this.cdn + item.image }))));
    }
    /**
     * Получить товар
     */
    async getProduct(productId) {
        return this._get(`/product/${productId}`).then((item) => (Object.assign(Object.assign({}, item), { image: this.cdn + item.image })));
    }
    /**
     * Создать заказ
     */
    async createOrder(order) {
        if (!order.items.length) {
            throw new Error('Список товаров в заказе пуст');
        }
        return this._post('/order', order);
    }
}
