export function isSelector(x) {
    return typeof x === 'string' && x.length > 1;
}
export function isEmpty(value) {
    return value === null || value === undefined;
}
export function isBoolean(v) {
    return typeof v === 'boolean';
}
export function pascalToKebab(value) {
    return value.replace(/([a-z0–9])([A-Z])/g, '$1-$2').toLowerCase();
}
/**
 * Проверка на простой объект
 */
export function isPlainObject(obj) {
    const prototype = Object.getPrototypeOf(obj);
    return prototype === Object.getPrototypeOf({}) || prototype === null;
}
/**
 * Возвращает список свойств объекта, кроме constructor.
 * @param obj объект, для которого нужно получить список свойств
 * @param filter - функция, которая будет вызвана для каждого свойства,
 *                 она должна вернуть true, если свойство нужно включить
 *                 в результат, и false, если нет.
 * @returns список имен свойств объекта, кроме constructor
 */
export function getObjectProperties(obj, filter) {
    return Object.entries(Object.getOwnPropertyDescriptors(Object.getPrototypeOf(obj)))
        .filter(([name, prop]) => filter ? filter(name, prop) : name !== 'constructor')
        .map(([name, prop]) => name);
}
export function formatCurrency(value) {
    if (value === null)
        return 'Бесценно';
    return `${value} синапсов`;
}
