import { ViewStates } from '../../types';
import { ensureElement } from '../../utils/html';
import { FormView } from './common/form';
export class PaymentView extends FormView {
    constructor(container, events) {
        super(container, events);
        this.container = container;
        this._online = ensureElement('button[name=card]', this.container);
        this._cash = ensureElement('button[name=cash]', this.container);
        this._address = ensureElement('input[name=address]', this.container);
        this._online.addEventListener('click', () => events.emit(ViewStates.orderPaymentChange, {
            field: 'payment',
            value: 'online',
        }));
        this._cash.addEventListener('click', () => events.emit(ViewStates.orderPaymentChange, {
            field: 'payment',
            value: 'cash',
        }));
    }
    set payment(value) {
        switch (value) {
            case 'cash':
                this._cash.classList.add('button_alt-active');
                this._online.classList.remove('button_alt-active');
                break;
            case 'online':
                this._online.classList.add('button_alt-active');
                this._cash.classList.remove('button_alt-active');
                break;
        }
    }
    set address(value) {
        this._address.value = value;
    }
}
