import { ensureElement } from '../../utils/html';
import { FormView } from './common/form';
export class ContactView extends FormView {
    constructor(container, events) {
        super(container, events);
        this.container = container;
        this._email = ensureElement('input[name=email]', this.container);
        this._phone = ensureElement('input[name=phone]', this.container);
    }
    set email(value) {
        this._email.value = value;
    }
    set phone(value) {
        this._phone.value = value;
    }
}
